mapper.select:
/* 카테고리 목록 조회 repository.selectCategoryList */ WITH RECURSIVE CAT_TREE AS ( -- 루트 SELECT CATEGORY_ID, CATEGORY_NAME, PARN_CAT_ID, CAT_LVL, SORT_ORD, CAST(LPAD(SORT_ORD, 10, '0') AS CHAR(2000)) AS SORT_PATH, 1 AS DEPTH FROM TB_CONTENT_CAT WHERE PARN_CAT_ID IS NULL
UNION ALL
-- 자식 (부모가 트리에 있을 때만) SELECT C.CATEGORY_ID, C.CATEGORY_NAME, C.PARN_CAT_ID, C.CAT_LVL, C.SORT_ORD, CONCAT(CT.SORT_PATH, '.', LPAD(C.SORT_ORD, 10, '0')), CT.DEPTH + 1 FROM TB_CONTENT_CAT C INNER JOIN CAT_TREE CT ON C.PARN_CAT_ID = CT.CATEGORY_ID ) SELECT * FROM CAT_TREE ORDER BY SORT_PATH

/* RAG 지식원천 문서 목록 조회 repository.selectDocRepositoryList 선택 카테고리 + 그 하위(자손) 카테고리에 속한 문서 포함 */ SELECT A.DOC_ID , A.DOC_TITLE , A.CATEGORY_ID , B.CATEGORY_NAME , A.AUTHOR , A.SEC_LVL , A.CONTENT , A.FILE_NAME , A.FILE_PATH , A.FILE_SIZE , A.FILE_TYPE , A.KEYWORDS , A.REF_URL , A.USE_YN , A.CREATE_DT , A.MODIFY_DT , ( SELECT COUNT(*) FROM TB_DS_DOC B WHERE 1=1 AND B.DOC_ID = A.DOC_ID ) AS DS_DOC_CNT FROM TB_DOC A INNER JOIN TB_CONTENT_CAT B ON B.CATEGORY_ID = A.CATEGORY_ID WHERE 1=1 AND A.USE_YN = 'Y' AND EXISTS ( WITH RECURSIVE CAT_SUBTREE AS ( SELECT CATEGORY_ID FROM TB_CONTENT_CAT WHERE CATEGORY_ID = #{categoryId} UNION ALL SELECT C.CATEGORY_ID FROM TB_CONTENT_CAT C INNER JOIN CAT_SUBTREE CS ON C.PARN_CAT_ID = CS.CATEGORY_ID ) SELECT 1 FROM CAT_SUBTREE CS WHERE CS.CATEGORY_ID = A.CATEGORY_ID )
AND ( A.CONTENT LIKE CONCAT('%', #{findContent}, '%') OR A.DOC_TITLE LIKE CONCAT('%', #{findContent}, '%') )
ORDER BY A.DOC_ID DESC
